def index_repo(repo: Path) -> None:
    print(f"Indexing {repo} …", flush=True)
    result = subprocess.run(
        ["context-engine", "index", str(repo)],
        cwd=repo,
        capture_output=True,
        text=True,
    )
    if result.returncode != 0:
        print(f"  [warn] index exited {result.returncode}: {result.stderr.strip()}", file=sys.stderr)
    else:
        print("  done.", flush=True)

def _parse_hook_output(raw: str) -> tuple[str, int, list[str]]:
    """Return (context, tokens, files_list) from raw hook stdout."""
    if not raw.strip():
        return "", 0, []
    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        return "", 0, []

    context: str = data.get("additionalContext", "")
    tokens = len(context) // 4

    # Parse [filename.py] markers that open each block
    files: list[str] = []
    for block in context.split("\n\n"):
        first = block.strip().splitlines()[0] if block.strip() else ""
        if first.startswith("[") and first.endswith("]"):
            fname = first[1:-1]
            if fname not in files:
                files.append(fname)

    return context, tokens, files

def baseline_tokens(repo: Path) -> int:
    total = 0
    for py_file in repo.rglob("*.py"):
        if any(part in _IGNORE_DIRS for part in py_file.parts):
            continue
        try:
            total += len(py_file.read_text(encoding="utf-8", errors="ignore")) // 4
        except OSError:
            pass
    return total

def _pct(baseline: int, with_ce: int) -> str:
    if baseline == 0:
        return "n/a"
    reduction = 100.0 * (baseline - with_ce) / baseline
    return f"{reduction:.1f}%"

def build_summary(baseline: int, rows: list[dict]) -> str:
    avg_tokens = sum(r["tokens"] for r in rows) / len(rows)
    avg_ms = sum(r["elapsed_ms"] for r in rows) / len(rows)
    avg_reduction = 100.0 * (baseline - avg_tokens) / baseline if baseline else 0
    return (
        f"\n**Baseline** (all .py tokens): {baseline:,}\n"
        f"**Avg injected tokens**: {avg_tokens:.0f}\n"
        f"**Avg reduction**: {avg_reduction:.1f}%\n"
        f"**Avg hook latency**: {avg_ms:.0f} ms\n"
    )

def _deterministic_context(query: str, result: dict, graph: dict) -> str:
    selected: list[str] = result.get("nodes_selected", [])
    if not selected:
        return ""
    node_dicts = resolve_nodes(selected, graph)
    ranked = rank_and_select(node_dicts, query)
    if not ranked:
        return ""
    return format_output(query, ranked)

def run_apply(
    query: str,
    graph: dict,
    project_root: Path,
    dry_run: bool = False,
    yes: bool = False,
) -> int:
    """
    Full apply pipeline: query → plan → diff → validate → apply.
    Returns exit code (0 = success, 1 = error).
    """
    from typer import echo, confirm

    backup_dir = project_root / ".cecl" / "backups"

    # Step 1: Context extraction + compression
    echo("Step 1/5  Extracting and compressing context...")
    result = run_query(query, graph)
    context = compress_context(query, result, graph)
    known_fns, missing_fns = _extract_fn_lists(result)

    if not context.strip():
        echo("  No relevant context found in graph - proceeding with empty context.")

    # Step 2: Planning
    echo("Step 2/5  Planning changes (Haiku)...")
    try:
        steps = plan(query, context)
    except RuntimeError as exc:
        echo(f"  Planning failed: {exc}", err=True)
        return 1

    echo(f"  {len(steps)} step(s) planned:")
    for s in steps:
        echo(f"    [{s['action'].upper()}] {s['file']} - {s['reason']}")

    # Step 3: Diff generation
    echo("Step 3/5  Generating diffs (Sonnet)...")
    try:
        diff_text = generate_diff(
            query=query,
            plan=steps,
            compressed_context=context,
            known_functions=known_fns,
            missing_functions=missing_fns,
            project_root=project_root,
        )
    except RuntimeError as exc:
        echo(f"  Diff generation failed: {exc}", err=True)
        return 1

    diffs = parse_diff(diff_text)
    if not diffs:
        echo("  No diffs produced by LLM.", err=True)
        return 1

    echo(f"  {len(diffs)} file diff(s) parsed.")

    # Step 4: Validation
    echo("Step 4/5  Validating diffs...")
    valid = True
    patch_ops: list[tuple] = []  # (FileDiff, Path, str, str)

    for diff in diffs:
        original = ""
        patched = ""
        target = project_root / diff.relative_path
        try:
            target, original, patched = apply_file_diff(diff, project_root)
        except FileNotFoundError as exc:
            if diff.is_new_file:
                target = project_root / diff.relative_path
                original = ""
                patched = _extract_create_content(diff.hunks)
            else:
                echo(f"  ERROR: {exc}", err=True)
                valid = False
                continue

        vr = validate_patch(original, patched, diff.relative_path)
        if not vr.ok:
            echo(f"  SYNTAX ERROR in {diff.relative_path}:", err=True)
            for err in vr.errors:
                echo(f"    {err}", err=True)
            valid = False
            continue

        if original:
            vdup = validate_no_duplicates(original, patched[len(original):] if len(patched) > len(original) else "")
            if not vdup.ok:
                echo(f"  DUPLICATE SYMBOL in {diff.relative_path}:", err=True)
                for err in vdup.errors:
                    echo(f"    {err}", err=True)
                valid = False
                continue

        echo(f"  OK  {diff.relative_path}")
        patch_ops.append((diff, target, original, patched))

    if not valid:
        echo("Validation failed - no files written.", err=True)
        return 1

    # Dry-run: show diffs only
    if dry_run:
        echo("\n-- DRY RUN: diff preview --")
        echo(diff_text)
        echo("-- No files written (--dry-run) --")
        return 0

    # Step 5: Apply
    if not yes:
        files_list = ", ".join(str(t) for _, t, _, _ in patch_ops)
        confirmed = confirm(f"\nApply changes to: {files_list}?")
        if not confirmed:
            echo("Aborted.")
            return 0

    echo("Step 5/5  Applying changes...")
    for _diff, target, original, patched in patch_ops:
        if original:
            bak = backup_file(target, backup_dir)
            echo(f"  Backed up {target.name} -> {bak.name}")
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(patched, encoding="utf-8")
        action = "Created" if not original else "Updated"
        echo(f"  {action} {target}")

    echo(f"\nDone. {len(patch_ops)} file(s) modified. Backups in {backup_dir}")
    return 0

def _collect_py_files(root: Path) -> list[Path]:
    """Walk root recursively, skipping ignored directories."""
    files: list[Path] = []
    for path in root.rglob("*.py"):
        if any(part in IGNORE_DIRS for part in path.parts):
            continue
        files.append(path)
    return sorted(files)

def _collect_js_files(root: Path) -> list[Path]:
    """Walk root recursively for JS/TS files, skipping ignored directories."""
    files: list[Path] = []
    for ext in JS_EXTENSIONS:
        for path in root.rglob(f"*{ext}"):
            if any(part in IGNORE_DIRS for part in path.parts):
                continue
            files.append(path)
    return sorted(set(files))

def main() -> None:
    if hasattr(sys.stdout, "reconfigure"):
        sys.stdout.reconfigure(encoding="utf-8", errors="replace")
    if hasattr(sys.stderr, "reconfigure"):
        sys.stderr.reconfigure(encoding="utf-8", errors="replace")
    app()

def _is_debug_log(stmt: ast.stmt) -> bool:
    """Return True if *stmt* is a bare print/logging call at statement level."""
    if not isinstance(stmt, ast.Expr) or not isinstance(stmt.value, ast.Call):
        return False
    func = stmt.value.func
    if isinstance(func, ast.Name):
        return func.id in _PRINT_NAMES
    if isinstance(func, ast.Attribute):
        return func.attr in _LOG_ATTRS
    return False

def _is_docstring(stmt: ast.stmt) -> bool:
    """Detect a bare string expression — typically a docstring."""
    return (
        isinstance(stmt, ast.Expr)
        and isinstance(stmt.value, ast.Constant)
        and isinstance(stmt.value.value, str)
    )

def _contains_keyword(node: ast.AST, keywords: set[str]) -> bool:
    """Check if any keyword appears as an identifier or string inside *node*."""
    if not keywords:
        return False
    for child in ast.walk(node):
        if isinstance(child, ast.Name) and child.id.lower() in keywords:
            return True
        if isinstance(child, ast.Attribute) and child.attr.lower() in keywords:
            return True
        if isinstance(child, ast.Constant) and isinstance(child.value, str):
            if any(kw in child.value.lower() for kw in keywords):
                return True
    return False

def _has_call(node: ast.AST) -> bool:
    """Return True if *node*'s subtree contains any function call."""
    return any(isinstance(c, ast.Call) for c in ast.walk(node))

def _is_pure_constant_rhs(node: ast.AST) -> bool:
    """True when RHS is a literal constant / tuple / list / dict of constants."""
    if isinstance(node, ast.Constant):
        return True
    if isinstance(node, (ast.Tuple, ast.List, ast.Set)):
        return all(isinstance(e, ast.Constant) for e in node.elts)
    if isinstance(node, ast.Dict):
        return all(
            (k is None or isinstance(k, ast.Constant)) and isinstance(v, ast.Constant)
            for k, v in zip(node.keys, node.values)
        )
    return False

def _should_keep(stmt: ast.stmt, keywords: set[str]) -> bool:
    """Decide whether a statement inside a function body survives compression."""
    # Drop prints / debug logs first.
    if _is_debug_log(stmt):
        return False

    # Drop docstrings unless they mention a keyword.
    if _is_docstring(stmt):
        return _contains_keyword(stmt, keywords)

    # Always keep control-flow, returns, raises, exit statements.
    if isinstance(stmt, (
        ast.Return, ast.Raise, ast.If, ast.Try, ast.For, ast.While,
        ast.With, ast.AsyncFor, ast.AsyncWith, ast.Assert,
        ast.Break, ast.Continue, ast.Pass,
    )):
        return True

    # Nested function/class definitions: keep their shape.
    if isinstance(stmt, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
        return True

    # Imports inside a function body are deliberate — keep them.
    if isinstance(stmt, (ast.Import, ast.ImportFrom)):
        return True

    # Assignments: drop pure-constant boilerplate without keyword signal.
    if isinstance(stmt, (ast.Assign, ast.AugAssign, ast.AnnAssign)):
        rhs = getattr(stmt, "value", None)
        if rhs is None:
            return True
        if _contains_keyword(stmt, keywords):
            return True
        if _has_call(rhs):
            return True
        if _is_pure_constant_rhs(rhs):
            return False
        return True  # complex expression — keep by default

    # Expression statements: keep only if they carry a keyword.
    if isinstance(stmt, ast.Expr):
        return _contains_keyword(stmt, keywords)

    return True

def _filter_body(body: list[ast.stmt], keywords: set[str]) -> list[ast.stmt]:
    """Return a filtered copy of *body* keeping only relevant statements."""
    result: list[ast.stmt] = []
    for stmt in body:
        if not _should_keep(stmt, keywords):
            continue

        # Recurse into control-flow bodies so we also prune their interiors.
        if isinstance(stmt, ast.If):
            stmt.body = _filter_body(stmt.body, keywords) or [ast.Pass()]
            stmt.orelse = _filter_body(stmt.orelse, keywords)
        elif isinstance(stmt, (ast.For, ast.While, ast.AsyncFor)):
            stmt.body = _filter_body(stmt.body, keywords) or [ast.Pass()]
            stmt.orelse = _filter_body(stmt.orelse, keywords)
        elif isinstance(stmt, ast.Try):
            stmt.body = _filter_body(stmt.body, keywords) or [ast.Pass()]
            for handler in stmt.handlers:
                handler.body = _filter_body(handler.body, keywords) or [ast.Pass()]
            stmt.orelse = _filter_body(stmt.orelse, keywords)
            stmt.finalbody = _filter_body(stmt.finalbody, keywords)
        elif isinstance(stmt, (ast.With, ast.AsyncWith)):
            stmt.body = _filter_body(stmt.body, keywords) or [ast.Pass()]

        result.append(stmt)
    return result

def _collect_callees(tree: ast.AST) -> list[str]:
    """Return deduplicated callee names found in *tree*, in AST order."""
    names: list[str] = []
    seen: set[str] = set()
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        func = node.func
        name: str | None = None
        if isinstance(func, ast.Name):
            name = func.id
        elif isinstance(func, ast.Attribute):
            name = func.attr
        if not name:
            continue
        if name in _PRINT_NAMES or name in _LOG_ATTRS:
            continue
        if name in seen:
            continue
        seen.add(name)
        names.append(name)
    return names

def _file_id(file_path: str) -> str:
    """Normalise a file path to a stable, forward-slash node ID."""
    return Path(file_path).as_posix()

def _symbol_id(file_path: str, symbol: str) -> str:
    """Return '<file>:<symbol>' — the canonical node ID for a symbol."""
    return f"{_file_id(file_path)}:{symbol}"

def build_graph(results: list[FileParseResult]) -> Graph:
    """Convert parsed file results into a node/edge graph.

    Node types  : file, function, method, class
    Edge types  : contains, has_method, calls, imports
    """
    nodes: dict[str, Node] = {}
    edges: list[Edge] = []
    seen_edges: set[tuple[str, str, str]] = set()

    # ------------------------------------------------------------------
    # Helpers
    # ------------------------------------------------------------------

    def add_node(node: Node) -> None:
        nid = node["id"]
        if nid not in nodes:
            nodes[nid] = node
        else:
            logger.debug("Duplicate node skipped: %s", nid)

    def add_edge(src: str, dst: str, edge_type: str) -> None:
        key = (src, dst, edge_type)
        if key not in seen_edges:
            seen_edges.add(key)
            edges.append({"from": src, "to": dst, "type": edge_type})

    # ------------------------------------------------------------------
    # Pass 1 — register every node; build lookup tables for edge resolution.
    # ------------------------------------------------------------------

    # Maps symbol_id → set of file-relative names defined in that file.
    # Used in pass 2 to decide whether a call edge is resolvable.
    file_local_names: dict[str, set[str]] = {}   # file_id → {symbol_name, ...}

    for result in results:
        fid = _file_id(result.path)
        local: set[str] = set()
        file_local_names[fid] = local

        # File node
        add_node({"id": fid, "type": "file"})

        # Function nodes
        for func in result.functions:
            sid = _symbol_id(result.path, func.name)
            add_node({
                "id": sid,
                "type": "function",
                "file": fid,
                "line": func.line,
                "code": func.code,
            })
            local.add(func.name)

        # Class + method nodes
        for cls in result.classes:
            cid = _symbol_id(result.path, cls.name)
            add_node({
                "id": cid,
                "type": "class",
                "file": fid,
                "line": cls.line,
            })
            local.add(cls.name)

            for method in cls.methods:
                qualified = f"{cls.name}.{method.name}"
                mid = _symbol_id(result.path, qualified)
                add_node({
                    "id": mid,
                    "type": "method",
                    "file": fid,
                    "line": method.line,
                    "code": method.code,
                })
                local.add(method.name)   # bare name for call resolution

    # ------------------------------------------------------------------
    # Pass 2 — emit edges.
    # ------------------------------------------------------------------

    # Build a reverse map: bare symbol name → list of node IDs that define it.
    # Lets us resolve cross-file calls when there is an explicit import.
    name_to_ids: dict[str, list[str]] = {}
    for node in nodes.values():
        if node["type"] in ("function", "method", "class"):
            bare = node["id"].split(":")[-1].split(".")[-1]
            name_to_ids.setdefault(bare, []).append(node["id"])

    for result in results:
        fid = _file_id(result.path)
        local_names = file_local_names[fid]

        # contains: file → function / class
        for func in result.functions:
            add_edge(fid, _symbol_id(result.path, func.name), "contains")

        for cls in result.classes:
            cid = _symbol_id(result.path, cls.name)
            add_edge(fid, cid, "contains")

            # has_method: class → method
            for method in cls.methods:
                qualified = f"{cls.name}.{method.name}"
                add_edge(cid, _symbol_id(result.path, qualified), "has_method")

        # imports: file → file  (resolve module name to a known file node)
        for imp in result.imports:
            # Try each candidate module path spelling.
            for candidate in _module_candidates(imp.module):
                if candidate in nodes:
                    add_edge(fid, candidate, "imports")
                    break

        # calls — only emit if callee is local OR explicitly imported.
        resolvable = local_names | result.imported_names

        for func in result.functions:
            caller_id = _symbol_id(result.path, func.name)
            for callee_name in func.calls:
                _maybe_add_call(
                    caller_id, callee_name, resolvable, fid,
                    result.path, local_names, name_to_ids, add_edge,
                )

        for cls in result.classes:
            for method in cls.methods:
                caller_id = _symbol_id(result.path, f"{cls.name}.{method.name}")
                for callee_name in method.calls:
                    _maybe_add_call(
                        caller_id, callee_name, resolvable, fid,
                        result.path, local_names, name_to_ids, add_edge,
                    )

    logger.info("Graph built: %d nodes, %d edges", len(nodes), len(edges))
    return {"nodes": list(nodes.values()), "edges": edges}

def _maybe_add_call(
    caller_id: str,
    callee_name: str,
    resolvable: set[str],
    caller_file_id: str,
    caller_path: str,
    local_names: set[str],
    name_to_ids: dict[str, list[str]],
    add_edge_fn: Any,
) -> None:
    """Emit a calls edge only when the callee is verifiably resolvable."""
    if callee_name not in resolvable:
        return

    if callee_name in local_names:
        # Prefer same-file symbol by building the qualified ID.
        callee_id = _symbol_id(caller_path, callee_name)
        # Might be a bare method name like "save" — also check "ClassName.save".
        if callee_id in _name_to_ids_local(caller_file_id, callee_name, name_to_ids):
            add_edge_fn(caller_id, callee_id, "calls")
            return
        # Fall back to any node in this file sharing the bare name.
        for nid in name_to_ids.get(callee_name, []):
            if nid.startswith(caller_file_id + ":"):
                add_edge_fn(caller_id, nid, "calls")
                return
    else:
        # Imported name — resolve to whichever node carries that bare name.
        candidates = name_to_ids.get(callee_name, [])
        for nid in candidates:
            add_edge_fn(caller_id, nid, "calls")

def _load_graph() -> dict | None:
    if not _GRAPH_PATH.exists():
        return None
    try:
        return json.loads(_GRAPH_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None

def _sig(code: str) -> str:
    for line in code.splitlines():
        s = line.strip()
        if s.startswith(("def ", "async def ")):
            return s.rstrip(":")
    return ""

def _body(code: str) -> list[str]:
    """Return non-empty, non-comment body lines with docstrings stripped."""
    lines = code.splitlines()

    # Find and skip the signature line
    sig_idx = 0
    for i, line in enumerate(lines):
        s = line.strip()
        if s.startswith(("def ", "async def ")):
            sig_idx = i
            break

    body = lines[sig_idx + 1:]

    # Strip leading docstring (handles single-line and multi-line)
    i = 0
    while i < len(body) and not body[i].strip():
        i += 1
    if i < len(body):
        first = body[i].strip()
        if first.startswith(('"""', "'''")):
            marker = first[:3]
            # Single-line docstring
            if first.count(marker) >= 2 and len(first) > 3:
                i += 1
            else:
                i += 1
                while i < len(body) and marker not in body[i]:
                    i += 1
                i += 1
        body = body[i:]

    return [
        l for l in body
        if l.strip() and not l.strip().startswith("#")
    ]

def _log(query: str, n_nodes: int, tokens: int, preview: str) -> None:
    try:
        _LOG_PATH.parent.mkdir(parents=True, exist_ok=True)
        ts = datetime.now().strftime("%Y-%m-%dT%H:%M:%S")
        line = (
            f"[{ts}] query={repr(query)} nodes={n_nodes} "
            f"tokens={tokens} preview={repr(preview[:100])}\n"
        )
        with _LOG_PATH.open("a", encoding="utf-8") as f:
            f.write(line)
    except Exception:
        pass

def _build_context(nodes: list[dict]) -> str:
    blocks: list[str] = []
    remaining = _TOKEN_BUDGET * 4  # chars

    for node in nodes[:_MAX_NODES]:
        if remaining <= 0:
            break
        block, used = _format_node(node, remaining)
        blocks.append(block)
        remaining -= used + 1  # +1 for separator

    return "\n\n".join(blocks)

def main() -> None:
    try:
        payload = json.loads(sys.stdin.read())
    except Exception:
        sys.exit(0)

    query: str = payload.get("prompt", "").strip()
    if not query:
        sys.exit(0)

    graph = _load_graph()
    if not graph:
        sys.exit(0)

    try:
        result = run_query(query, graph)
        selected: list[str] = result.get("nodes_selected", [])
        all_ids = [n["id"] for n in graph.get("nodes", []) if "id" in n]
        pool_ids = selected if selected else all_ids

        node_dicts = resolve_nodes(pool_ids, graph)
        ranked = rank_and_select(node_dicts, query, top_n=_MAX_NODES)
    except Exception:
        sys.exit(0)

    if not ranked:
        sys.exit(0)

    context = _build_context(ranked)
    _log(query, len(ranked), len(context) // 4, context)
    if context.strip():
        sys.stdout.write(json.dumps({"additionalContext": context}))

    sys.exit(0)

def detect_intent(query: str) -> str:
    """Return one of: ``debug`` | ``explain`` | ``generate`` | ``lookup``.

    Detection order: phrase patterns → single-word triggers → fallback (lookup).
    Priority across intents: debug > explain > generate > lookup.
    """
    q = query.lower()
    tokens = set(q.split())

    for intent in ("debug", "explain", "generate"):
        for phrase in _INTENT_PHRASES.get(intent, ()):
            if phrase in q:
                return intent

    for intent in ("debug", "explain", "generate"):
        if tokens & _INTENT_WORDS[intent]:
            return intent

    return "lookup"

def build_flow(
    nodes: list[Node],
    edges: list[Edge],
    entry_ids: list[str],
) -> list[str]:
    """Return bare function/method names in topological call order.

    Restricted to the kept function/method nodes and ``calls`` edges between
    them.  Entry points seed the queue first.  Cycles are appended at the end.
    """
    kept: dict[str, Node] = {
        n["id"]: n
        for n in nodes
        if n.get("type") in ("function", "method")
    }
    if not kept:
        return []

    succ: dict[str, list[str]] = {nid: [] for nid in kept}
    in_deg: dict[str, int] = {nid: 0 for nid in kept}
    for edge in edges:
        src, dst, etype = edge["from"], edge["to"], edge.get("type", "")
        if etype == "calls" and src in kept and dst in kept:
            succ[src].append(dst)
            in_deg[dst] += 1

    # Seed queue: entry points with no internal callers first.
    queue: deque[str] = deque()
    queued: set[str] = set()
    for eid in entry_ids:
        if eid in kept and in_deg[eid] == 0:
            queue.append(eid)
            queued.add(eid)
    for nid in kept:
        if nid not in queued and in_deg[nid] == 0:
            queue.append(nid)
            queued.add(nid)

    ordered: list[str] = []
    visited: set[str] = set()
    while queue:
        nid = queue.popleft()
        if nid in visited:
            continue
        visited.add(nid)
        _, _, name = nid.rpartition(":")
        ordered.append(name)
        for callee in succ[nid]:
            in_deg[callee] -= 1
            if in_deg[callee] == 0 and callee not in visited:
                queue.append(callee)

    # Append cycle members last.
    for nid in kept:
        if nid not in visited:
            _, _, name = nid.rpartition(":")
            ordered.append(name)

    return ordered

def extract_failures(nodes: list[Node]) -> list[dict[str, str]]:
    """Scan code snippets for AST-level failure patterns.

    Detected patterns
    -----------------
    * ``raise <Exc>``     — explicit exception raises.
    * ``except <Exc>``    — exception handlers (potential silent swallowers).
    * ``if <guard>: raise / return False/None``  — validation checks.

    Returns a deduplicated list of ``{"node", "kind", "detail"}`` dicts.
    """
    results: list[dict[str, str]] = []
    seen: set[tuple[str, str, str]] = set()

    def _add(node_name: str, kind: str, detail: str) -> None:
        key = (node_name, kind, detail)
        if key not in seen:
            seen.add(key)
            results.append({"node": node_name, "kind": kind, "detail": detail})

    for node in nodes:
        code = node.get("code", "")
        if not code:
            continue
        _, _, name = node["id"].rpartition(":")

        try:
            tree = ast.parse(textwrap.dedent(code).strip())
        except SyntaxError:
            continue

        for child in ast.walk(tree):
            if isinstance(child, ast.Raise) and child.exc is not None:
                try:
                    exc_text = ast.unparse(child.exc)
                except Exception:
                    exc_text = "..."
                _add(name, "raises", exc_text)

            elif isinstance(child, ast.ExceptHandler) and child.type is not None:
                try:
                    exc_type = ast.unparse(child.type)
                except Exception:
                    exc_type = "Exception"
                _add(name, "catches", exc_type)

            elif isinstance(child, ast.If):
                body_is_guard = any(
                    isinstance(s, ast.Raise)
                    or (
                        isinstance(s, ast.Return)
                        and (
                            s.value is None
                            or (isinstance(s.value, ast.Constant)
                                and s.value.value in (False, None))
                        )
                    )
                    for s in child.body
                )
                if body_is_guard:
                    try:
                        cond = ast.unparse(child.test)
                    except Exception:
                        cond = "..."
                    _add(name, "check", cond)

    return results

def debug_hints(
    failures: list[dict[str, str]],
    keywords: list[str],
) -> list[str]:
    """Return up to 6 actionable debug hints based on failures and keywords."""
    signal: set[str] = set(keywords)
    for f in failures:
        signal.update(f["detail"].lower().split())

    hints: list[str] = []
    for trigger_set, hint in _HINT_RULES:
        if trigger_set & signal:
            hints.append(hint)

    for f in failures:
        if len(hints) >= 6:
            break
        if f["kind"] == "raises":
            hints.append(
                f"{f['node']} raises {f['detail']} — trace the call site"
            )
        elif f["kind"] == "catches":
            hints.append(
                f"{f['node']} silently catches {f['detail']} — inspect handler"
            )

    return hints[:6]

def suggest_implementation(keywords: list[str]) -> list[str]:
    """Return ordered implementation steps for a generate-mode query."""
    kw = set(keywords)
    if kw & {"login", "auth", "authenticate", "signin", "jwt", "token", "password"}:
        return _GENERATE_TEMPLATES["auth"]
    if kw & {"user", "account", "profile", "register", "signup"}:
        return _GENERATE_TEMPLATES["user"]
    if kw & {"db", "database", "sql", "model", "schema", "migration"}:
        return _GENERATE_TEMPLATES["db"]
    return _GENERATE_TEMPLATES["default"]

def group_components(nodes: list[Node]) -> dict[str, list[str]]:
    """Bucket function/method nodes into functional layers by name pattern."""
    groups: dict[str, list[str]] = {}
    for node in nodes:
        if node.get("type") not in ("function", "method"):
            continue
        _, _, name = node["id"].rpartition(":")
        name_lower = name.lower()
        placed = False
        for layer_name, signals in _LAYER_SIGNALS:
            if any(sig in name_lower for sig in signals):
                groups.setdefault(layer_name, []).append(name)
                placed = True
                break
        if not placed:
            groups.setdefault("Other", []).append(name)
    return groups

def _detect_framework(nodes: list[Node]) -> str:
    """Detect web framework from code snippets. Scans all supplied nodes."""
    for node in nodes:
        code = node.get("code", "")
        if not code:
            continue
        if any(sig in code for sig in ("APIRouter", "Depends(", "HTTPException", "fastapi")):
            return "fastapi"
        if "fastapi" in code.lower():
            return "fastapi"
        if any(sig in code for sig in ("Blueprint", "@app.route", "Flask(")):
            return "flask"
        if "flask" in code.lower():
            return "flask"
        if any(sig in code for sig in ("HttpResponse", "render(request", "models.Model")):
            return "django"
        if "django" in code.lower():
            return "django"
    return "generic"

def _detect_async(nodes: list[Node]) -> bool:
    """Return True if any node contains real async code (not just docstring mentions)."""
    for node in nodes:
        code = node.get("code", "")
        if _ASYNC_PATTERN.search(code) or _AWAIT_PATTERN.search(code):
            return True
    return False

def _find_fn(nodes: list[Node], fallback: str, *signals: str) -> tuple[str, bool]:
    """Return (name, found_in_graph).

    Searches function/method nodes for any name containing a signal token.
    When not found, returns (fallback, False) so callers can surface MISSING.
    """
    for node in nodes:
        if node.get("type") not in ("function", "method"):
            continue
        _, _, name = node["id"].rpartition(":")
        if any(sig in name.lower() for sig in signals):
            return name, True
    return fallback, False

def _short_path(fpath: str) -> str:
    """Return last two path segments, forward-slash separated."""
    parts = re.split(r"[/\\]", fpath.strip())
    return "/".join(p for p in parts[-2:] if p)

def _gen_generic_snippet(name: str, framework: str, is_async: bool) -> str:
    fn_name = re.sub(r"[^a-z0-9_]", "_", name.lower()).strip("_")
    a = "async " if is_async else ""
    aw = "await " if is_async else ""
    if framework == "fastapi":
        return (
            f'@router.post("/{fn_name}")\n'
            f'{a}def {fn_name}(data: dict):\n'
            f'    result = {aw}process_{fn_name}(data)\n'
            f'    return result'
        )
    return (
        f'{a}def {fn_name}(data):\n'
        f'    result = {aw}process(data)\n'
        f'    return result'
    )

def _file_to_module(fpath: str) -> str:
    """Convert an absolute file path to a dotted Python import path.

    Anchoring priority:
    1. If "app" is a path segment, anchor there (FastAPI/Django project convention).
    2. Otherwise find the first all-lowercase Python package name segment.

    Example: ``C:/Users/HP/project/app/core/security.py`` → ``app.core.security``
    Example: ``C:/Users/HP/project/context_engine/cli.py`` → ``context_engine.cli``
    """
    normalized = fpath.replace("\\", "/")
    parts = normalized.split("/")
    if parts:
        parts[-1] = re.sub(r"\.pyi?$", "", parts[-1])
    # Prefer "app" as anchor — avoids long system-path prefixes
    if "app" in parts:
        idx = parts.index("app")
        return ".".join(p for p in parts[idx:] if p)
    for i, part in enumerate(parts):
        if re.match(r"^[a-z][a-z0-9_]*$", part):
            return ".".join(p for p in parts[i:] if p)
    return ".".join(p for p in parts if p)

def find_integration_target(
    all_nodes: list[Node],
    keywords: list[str],
) -> dict[str, str]:
    """Return the best existing file to add generated code to, or suggest a new one.

    Returns ``{"action": "add"|"create", "file": "<path>"}``.
    """
    router_files: list[str] = []
    for node in all_nodes:
        if node.get("type") != "file":
            continue
        fpath = node["id"]
        stem = re.split(r"[/\\]", fpath)[-1]
        stem = re.sub(r"\.(py|js|ts)$", "", stem, flags=re.IGNORECASE).lower()
        if any(tok in stem for tok in _ROUTER_TOKENS):
            router_files.append(fpath)

    kw = set(keywords)
    if router_files:
        for f in router_files:
            f_lower = f.lower()
            if kw & {"login", "auth", "signin"} and any(t in f_lower for t in ("auth", "login", "security")):
                return {"action": "add", "file": _short_path(f)}
        return {"action": "add", "file": _short_path(router_files[0])}

    if kw & {"login", "auth", "authenticate", "signin"}:
        return {"action": "create", "file": "app/api/routes/auth.py"}
    if kw & {"user", "account", "profile", "register"}:
        return {"action": "create", "file": "app/api/routes/users.py"}
    return {"action": "create", "file": "app/api/routes/new.py"}

def generate_schema(keywords: list[str], framework: str) -> str:
    """Return a Pydantic BaseModel class definition for the request body.

    Only emitted for FastAPI (the only framework where Pydantic request models
    are idiomatic).  Returns an empty string for all other frameworks.
    """
    if framework != "fastapi":
        return ""
    kw = set(keywords)
    if kw & {"login", "auth", "authenticate", "signin"}:
        return (
            "class LoginRequest(BaseModel):\n"
            "    email: str\n"
            "    password: str"
        )
    if kw & {"user", "register", "signup", "account"}:
        return (
            "class CreateUserRequest(BaseModel):\n"
            "    email: str\n"
            "    password: str\n"
            "    username: str | None = None"
        )
    return ""

def generate_imports(
    framework: str,
    is_async: bool,
    fn_names: list[str],
    all_nodes: list[Node],
    has_schema: bool = False,
) -> list[str]:
    """Generate properly grouped import statements.

    Group 1 — third-party (fastapi, pydantic, sqlalchemy, …), alphabetical.
    Group 2 — local project imports (one ``from <module> import …`` per file).
    Groups separated by a blank line.
    """
    third_party: list[str] = []
    if framework == "fastapi":
        third_party.append("from fastapi import APIRouter, Depends, HTTPException")
        if has_schema:
            third_party.append("from pydantic import BaseModel")
        if is_async:
            third_party.append("from sqlalchemy.ext.asyncio import AsyncSession")
    elif framework == "flask":
        third_party.append("from flask import Blueprint, abort, jsonify, request")
    elif has_schema:
        third_party.append("from pydantic import BaseModel")

    # Build fn_name → source_file map from graph
    file_map: dict[str, str] = {}
    for node in all_nodes:
        if node.get("type") not in ("function", "method"):
            continue
        _, _, name = node["id"].rpartition(":")
        if name in fn_names and name not in file_map:
            fpath = node.get("file", "")
            if fpath:
                file_map[name] = fpath

    # Group by module path, emit one from-import per module
    module_fns: dict[str, list[str]] = {}
    for name, fpath in file_map.items():
        module = _file_to_module(fpath)
        module_fns.setdefault(module, []).append(name)

    local: list[str] = []
    for module in sorted(module_fns):
        # Skip any module that resolves to a known third-party package
        pkg = module.split(".")[0]
        if pkg in _THIRD_PARTY_PREFIXES:
            continue
        fns = ", ".join(sorted(module_fns[module]))
        local.append(f"from {module} import {fns}")

    lines: list[str] = []
    lines.extend(third_party)
    if third_party and local:
        lines.append("")
    lines.extend(local)
    return lines

def generate_missing_impl(missing_deps: list[str], is_async: bool) -> str:
    """Return concatenated minimal implementations for each missing dependency."""
    impls: list[str] = []
    for dep in missing_deps:
        fn_name = dep.split("(")[0].strip()
        if fn_name in _MISSING_IMPL_TEMPLATES:
            sync_impl, async_impl = _MISSING_IMPL_TEMPLATES[fn_name]
            impls.append(async_impl if is_async else sync_impl)
    return "\n\n".join(impls)

def generate_debug_fix(
    failures: list[dict[str, str]],
    keywords: list[str],
) -> tuple[list[str], list[str], str]:
    """Return (checks, root_causes, fix_code) for debug output.

    Matches the combined keyword+failure signal against ``_DEBUG_FIX_RULES``.
    Falls back to a generic trace snippet when no rule fires.
    """
    signal: set[str] = set(keywords)
    for f in failures:
        signal.update(f["detail"].lower().split())

    for trigger_set, check, root_cause, fix in _DEBUG_FIX_RULES:
        if trigger_set & signal:
            return [check], [root_cause], fix

    # Fallback: generate a minimal trace wrapper around the first failure site.
    if failures:
        f = failures[0]
        if f["kind"] == "raises":
            fix = (
                f"try:\n    result = {f['node']}(...)\n"
                f"except Exception as e:\n    print(f'Error in {f['node']}: {{e}}')\n    raise"
            )
        elif f["kind"] == "catches":
            fix = (
                f"import logging\nlogger = logging.getLogger(__name__)\n\n"
                f"try:\n    ...\nexcept {f['detail']} as e:\n"
                f"    logger.exception('Unexpected error in {f['node']}')\n    raise"
            )
        else:
            fix = f"assert <condition>, '<condition> must hold before calling {f['node']}()'"
        return (
            [f"Inspect failure site: {f['node']}"],
            [f"{f['node']} {f['kind']}: {f['detail']}"],
            fix,
        )

    return [], [], ""

def _bare(node_id: str) -> str:
    _, _, name = node_id.rpartition(":")
    return name or node_id

def _format_debug(
    result: Mapping[str, Any],
    flow: list[str],
    failures: list[dict[str, str]],
) -> str:
    lines: list[str] = [
        "intent        : DEBUG",
        f"keywords      : {', '.join(result.get('keywords', []))}",
        "",
    ]

    if result.get("entry_points"):
        lines.append("ENTRY POINTS:")
        for ep in result["entry_points"]:
            lines.append(f"  {_bare(ep)}")
        lines.append("")

    # Annotated failure path
    if flow:
        failure_map: dict[str, list[str]] = {}
        for f in failures:
            if f["kind"] == "raises":
                note = f"raises {f['detail']}"
            elif f["kind"] == "catches":
                note = f"catches {f['detail']}"
            else:
                note = f"guards on `{f['detail']}`"
            failure_map.setdefault(f["node"], []).append(note)

        lines.append("FAILURE PATH:")
        for fn in flow:
            notes = failure_map.get(fn, [])
            suffix = "  ->  " + ", ".join(notes) if notes else "  ->  OK"
            lines.append(f"  {fn}{suffix}")
        lines.append("")

    checks, root_causes, fix_code = generate_debug_fix(failures, result.get("keywords", []))

    if checks:
        lines.append("CHECK:")
        for c in checks:
            lines.append(f"  - {c}")
        lines.append("")

    if root_causes:
        lines.append("ROOT CAUSE (LIKELY):")
        for rc in root_causes:
            lines.append(f"  - {rc}")
        lines.append("")

    if fix_code:
        lines += ["FIX:", _DIVIDER, fix_code, _DIVIDER, ""]

    nodes_sel = result.get("nodes_selected", [])
    lines += [
        f"nodes         : {len(nodes_sel)}",
        _token_line(result),
        "",
    ]

    if result.get("context"):
        lines += [_DIVIDER, result["context"], _DIVIDER]

    return "\n".join(lines)

def _format_explain(
    result: Mapping[str, Any],
    flow: list[str],
) -> str:
    kws = result.get("keywords", [])
    domain = kws[0].upper() if kws else "CODE"

    lines: list[str] = [
        "intent        : EXPLAIN",
        f"keywords      : {', '.join(kws)}",
        "",
        f"{domain} FLOW:",
    ]

    if flow:
        for i, step in enumerate(flow, 1):
            lines.append(f"  {i}. {step}")
    else:
        lines.append("  (no flow data - run `context-engine index` first)")

    lines += [
        "",
        f"nodes         : {len(result.get('nodes_selected', []))}",
        _token_line(result),
        "",
    ]

    if result.get("context"):
        lines += [_DIVIDER, result["context"], _DIVIDER]

    return "\n".join(lines)

def _format_lookup(result: Mapping[str, Any]) -> str:
    lines: list[str] = [
        "intent        : LOOKUP",
        f"keywords      : {', '.join(result.get('keywords', []))}",
        "",
    ]

    eps = result.get("entry_points", [])
    if eps:
        lines.append(f"entry points  : {len(eps)}")
        for ep in eps:
            lines.append(f"  * {_bare(ep)}")
        lines.append("")

    cat_counts = Counter(result.get("categories", {}).values())
    lines.append(
        f"nodes         : {len(result.get('nodes_selected', []))}  "
        + "  ".join(f"{k}={v}" for k, v in sorted(cat_counts.items()))
    )

    inline_count = sum(len(v) for v in result.get("inline_hints", {}).values())
    if inline_count:
        lines.append(f"inline hints  : {inline_count}")

    lines += ["", _token_line(result), ""]

    if result.get("context"):
        lines += [_DIVIDER, result["context"], _DIVIDER]

    return "\n".join(lines)

def format_intent_output(
    result: Mapping[str, Any],
    graph: Mapping[str, Any],
) -> str:
    """Produce intent-aware CLI output for a query result.

    Dispatches to one of four formatters:

    * ``debug``    → CALL FLOW + POTENTIAL FAILURES + DEBUG HINTS + code
    * ``explain``  → numbered FLOW + code
    * ``generate`` → EXISTING COMPONENTS + SUGGESTED IMPLEMENTATION + code
    * ``lookup``   → entry points + stats + code  (current behaviour)
    """
    intent = result.get("intent", "lookup")
    node_map: dict[str, Any] = {n["id"]: n for n in graph.get("nodes", [])}
    graph_nodes: list[Node] = list(node_map.values())
    kept: list[Node] = [
        node_map[nid]
        for nid in result.get("nodes_selected", [])
        if nid in node_map
    ]
    edges: list[Edge] = graph.get("edges", [])
    entry_ids: list[str] = result.get("entry_points", [])

    flow = build_flow(kept, edges, entry_ids)
    failures = extract_failures(kept)

    if intent == "debug":
        return _format_debug(result, flow, failures)
    if intent == "explain":
        return _format_explain(result, flow)
    if intent == "generate":
        return _format_generate(result, kept, graph_nodes)
    return _format_lookup(result)

def _get_parser(lang: str):
    global _AVAILABLE
    if not _AVAILABLE:
        return None
    if lang in _PARSERS:
        return _PARSERS[lang]
    try:
        from tree_sitter_language_pack import get_parser  # type: ignore
        p = get_parser(lang)
        _PARSERS[lang] = p
        return p
    except Exception as exc:
        logger.debug("tree-sitter parser unavailable for %s: %s", lang, exc)
        _AVAILABLE = False
        return None

def _lang_for(path: Path) -> str:
    """Return the tree-sitter language name for a given file extension."""
    ext = path.suffix.lower()
    if ext in (".ts", ".tsx"):
        return "typescript"
    return "javascript"

def _text(node) -> str:
    """Decode node bytes to str."""
    return (node.text or b"").decode("utf-8", errors="replace")

def _source_slice(source: str, node) -> str:
    """Return the exact source lines covered by *node*."""
    lines = source.splitlines(keepends=True)
    start_row, _ = node.start_point
    end_row, end_col = node.end_point
    if start_row == end_row:
        return lines[start_row][: end_col] if start_row < len(lines) else ""
    chunk = lines[start_row: end_row + 1]
    if chunk:
        chunk[-1] = chunk[-1][: end_col]
    return "".join(chunk)

def _child_by_type(node, *types: str):
    for child in node.children:
        if child.type in types:
            return child
    return None

def _extract_calls(node) -> list[str]:
    """Walk subtree and collect deduplicated callee names."""
    seen: dict[str, None] = {}

    def walk(n):
        if n.type == "call_expression":
            fn = n.children[0] if n.children else None
            if fn is not None:
                if fn.type == "identifier":
                    seen[_text(fn)] = None
                elif fn.type == "member_expression":
                    # foo.bar() — record "bar" (the method name)
                    prop = fn.children[-1] if fn.children else None
                    if prop and prop.type in ("property_identifier", "identifier"):
                        seen[_text(prop)] = None
        for child in n.children:
            walk(child)

    walk(node)
    return list(seen)

def _extract_imports(root) -> tuple[list[ImportInfo], set[str]]:
    imports: list[ImportInfo] = []
    imported_names: set[str] = set()

    for node in root.children:
        # ES6: import { foo, bar } from "./module"
        # ES6: import DefaultExport from "module"
        # ES6: import * as ns from "module"
        if node.type == "import_statement":
            module = ""
            names: list[str] = []

            # find the source string
            for child in node.children:
                if child.type == "string":
                    module = _text(child).strip("'\"")

            clause = _child_by_type(node, "import_clause")
            if clause:
                for child in clause.children:
                    if child.type == "identifier":
                        # default import: import Foo from "..."
                        names.append(_text(child))
                        imported_names.add(_text(child))
                    elif child.type == "named_imports":
                        for spec in child.children:
                            if spec.type == "import_specifier":
                                # grab the local name (last identifier in specifier)
                                idents = [c for c in spec.children if c.type == "identifier"]
                                if idents:
                                    local = _text(idents[-1])
                                    names.append(local)
                                    imported_names.add(local)
                    elif child.type == "namespace_import":
                        # import * as ns
                        idents = [c for c in child.children if c.type == "identifier"]
                        if idents:
                            ns = _text(idents[-1])
                            names.append(ns)
                            imported_names.add(ns)

            if module:
                imports.append(ImportInfo(module=module, names=names))

        # CommonJS: const x = require("module")
        elif node.type in ("lexical_declaration", "variable_declaration"):
            for decl in node.children:
                if decl.type != "variable_declarator":
                    continue
                rhs_nodes = [c for c in decl.children if c.type == "call_expression"]
                for call in rhs_nodes:
                    fn_node = call.children[0] if call.children else None
                    if fn_node and fn_node.type == "identifier" and _text(fn_node) == "require":
                        args = _child_by_type(call, "arguments")
                        if args:
                            strings = [c for c in args.children if c.type == "string"]
                            if strings:
                                module = _text(strings[0]).strip("'\"")
                                # local binding name
                                lhs = decl.children[0] if decl.children else None
                                name = _text(lhs) if lhs and lhs.type == "identifier" else ""
                                imports.append(ImportInfo(module=module, names=[name] if name else []))
                                if name:
                                    imported_names.add(name)

    return imports, imported_names

def _collect_functions_and_classes(
    root,
    source: str,
    file_path: str,
) -> tuple[list[FunctionInfo], list[ClassInfo]]:
    functions: list[FunctionInfo] = []
    classes: list[ClassInfo] = []

    def fn_name_from_node(node) -> str | None:
        """Return function name for any of the function node shapes."""
        # function_declaration / function_expression with explicit name
        ident = _child_by_type(node, "identifier", "type_identifier")
        if ident:
            return _text(ident)
        return None

    def process_top_level(node):
        t = node.type

        # ── named function declaration ────────────────────────────────────
        if t == "function_declaration":
            name = fn_name_from_node(node)
            if name:
                functions.append(FunctionInfo(
                    name=name,
                    file=file_path,
                    line=node.start_point[0] + 1,
                    code=_source_slice(source, node),
                    calls=_extract_calls(node),
                ))

        # ── export statement — unwrap and recurse ─────────────────────────
        elif t == "export_statement":
            for child in node.children:
                if child.type in (
                    "function_declaration", "class_declaration",
                    "lexical_declaration", "variable_declaration",
                ):
                    process_top_level(child)

        # ── const/let/var foo = function / arrow ─────────────────────────
        elif t in ("lexical_declaration", "variable_declaration"):
            for decl in node.children:
                if decl.type != "variable_declarator":
                    continue
                lhs = decl.children[0] if decl.children else None
                if lhs is None or lhs.type not in ("identifier", "type_identifier"):
                    continue
                name = _text(lhs)
                rhs = next(
                    (c for c in decl.children if c.type in ("arrow_function", "function")),
                    None,
                )
                if rhs is not None:
                    functions.append(FunctionInfo(
                        name=name,
                        file=file_path,
                        line=decl.start_point[0] + 1,
                        code=_source_slice(source, decl),
                        calls=_extract_calls(rhs),
                    ))

        # ── class declaration ─────────────────────────────────────────────
        elif t == "class_declaration":
            name_node = _child_by_type(node, "identifier", "type_identifier")
            if name_node is None:
                return
            class_name = _text(name_node)
            methods: list[MethodInfo] = []

            body = _child_by_type(node, "class_body")
            if body:
                for item in body.children:
                    if item.type != "method_definition":
                        continue
                    mname_node = _child_by_type(item, "property_identifier", "identifier")
                    if mname_node is None:
                        continue
                    mname = _text(mname_node)
                    methods.append(MethodInfo(
                        name=mname,
                        class_name=class_name,
                        file=file_path,
                        line=item.start_point[0] + 1,
                        code=_source_slice(source, item),
                        calls=_extract_calls(item),
                    ))

            classes.append(ClassInfo(
                name=class_name,
                file=file_path,
                line=node.start_point[0] + 1,
                methods=methods,
            ))

        # ── TypeScript: interface / type alias (treated as class-like) ───
        elif t == "interface_declaration":
            name_node = _child_by_type(node, "type_identifier")
            if name_node:
                classes.append(ClassInfo(
                    name=_text(name_node),
                    file=file_path,
                    line=node.start_point[0] + 1,
                    methods=[],
                ))

    for child in root.children:
        process_top_level(child)

    return functions, classes

def _load_graph() -> dict | None:
    global _graph_cache
    if _graph_cache is not None:
        return _graph_cache
    if not _GRAPH_PATH.exists():
        return None
    _graph_cache = json.loads(_GRAPH_PATH.read_text(encoding="utf-8"))
    return _graph_cache

def _get_snippet(source: str, node: ast.AST) -> str:
    """Return the exact source segment for *node*, with line-slice fallback."""
    snippet = ast.get_source_segment(source, node)
    if snippet:
        return snippet
    # Fallback: slice by line numbers when get_source_segment fails.
    lines = source.splitlines()
    start = node.lineno - 1  # type: ignore[attr-defined]
    end = getattr(node, "end_lineno", node.lineno)  # type: ignore[attr-defined]
    return "\n".join(lines[start:end])

def _extract_calls(node: ast.AST) -> list[str]:
    """Return deduplicated bare callee names found in *node*'s subtree."""
    calls: list[str] = []
    for child in ast.walk(node):
        if not isinstance(child, ast.Call):
            continue
        func = child.func
        if isinstance(func, ast.Name):
            calls.append(func.id)
        elif isinstance(func, ast.Attribute):
            calls.append(func.attr)
    return list(dict.fromkeys(calls))

def _parse_import_stmt(node: ast.Import | ast.ImportFrom) -> ImportInfo:
    if isinstance(node, ast.Import):
        # `import a, b` → one ImportInfo per alias keeps things uniform
        return ImportInfo(
            module=", ".join(alias.name for alias in node.names),
            names=[],
        )
    module = node.module or ""
    names = [alias.name for alias in node.names]
    return ImportInfo(module=module, names=names)

def _collect_imported_names(imports: list[ImportInfo]) -> set[str]:
    """Build the flat set of names that are brought into scope by imports."""
    names: set[str] = set()
    for imp in imports:
        if imp.names:
            # `from x import a, b` → {a, b}
            names.update(imp.names)
        else:
            # `import a.b.c` → top-level name is a
            top = imp.module.split(",")[0].strip().split(".")[0]
            if top:
                names.add(top)
    return names

def _top_level_functions(tree: ast.Module) -> list[ast.FunctionDef | ast.AsyncFunctionDef]:
    """Return only module-level functions (not methods inside classes)."""
    result = []
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            result.append(node)
    return result

def parse_file(path: Path) -> FileParseResult | None:
    """Parse a single .py file and return structured metadata."""
    rel = str(path)
    try:
        source = path.read_text(encoding="utf-8", errors="replace")
        tree = ast.parse(source, filename=rel)
    except SyntaxError as exc:
        logger.warning("Syntax error in %s: %s", rel, exc)
        return None
    except Exception as exc:
        logger.warning("Cannot parse %s: %s", rel, exc)
        return None

    result = FileParseResult(path=rel, source=source)

    # Collect imports first so we can resolve names later.
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            result.imports.append(_parse_import_stmt(node))

    result.imported_names = _collect_imported_names(result.imports)

    # Classes — iterate top-level nodes to preserve class scope.
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, ast.ClassDef):
            methods: list[MethodInfo] = []
            for item in node.body:
                if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    methods.append(
                        MethodInfo(
                            name=item.name,
                            class_name=node.name,
                            file=rel,
                            line=item.lineno,
                            code=_get_snippet(source, item),
                            calls=_extract_calls(item),
                        )
                    )
            result.classes.append(
                ClassInfo(name=node.name, file=rel, line=node.lineno, methods=methods)
            )

    # Module-level functions only (skip methods already captured above).
    for node in _top_level_functions(tree):
        result.functions.append(
            FunctionInfo(
                name=node.name,
                file=rel,
                line=node.lineno,
                code=_get_snippet(source, node),
                calls=_extract_calls(node),
            )
        )

    return result

def parse_diff(diff_text: str) -> list[FileDiff]:
    """Parse a unified diff string into FileDiff objects."""
    # Strip markdown fences if LLM wrapped output
    diff_text = re.sub(r"^```[^\n]*\n", "", diff_text, flags=re.MULTILINE)
    diff_text = re.sub(r"^```\s*$", "", diff_text, flags=re.MULTILINE)

    diffs: list[FileDiff] = []
    current: FileDiff | None = None
    current_hunk: Hunk | None = None

    for line in diff_text.splitlines():
        if line.startswith("--- "):
            if current_hunk and current:
                current.hunks.append(current_hunk)
                current_hunk = None
            orig = line[4:].strip()
            current = FileDiff(orig_path=orig, new_path="")
            diffs.append(current)
        elif line.startswith("+++ ") and current is not None:
            current.new_path = line[4:].strip()
        elif line.startswith("@@ ") and current is not None:
            if current_hunk:
                current.hunks.append(current_hunk)
            m = _HUNK_HEADER.match(line)
            if m:
                os_, oc, ns, nc = m.group(1), m.group(2), m.group(3), m.group(4)
                current_hunk = Hunk(
                    orig_start=int(os_),
                    orig_count=int(oc) if oc is not None else 1,
                    new_start=int(ns),
                    new_count=int(nc) if nc is not None else 1,
                )
        elif current_hunk is not None:
            if line.startswith(("+", "-", " ")):
                current_hunk.lines.append(line)
            elif line == "\\ No newline at end of file":
                pass  # ignore

    if current_hunk and current:
        current.hunks.append(current_hunk)

    return [d for d in diffs if d.new_path]

def _extract_create_content(hunks: list[Hunk]) -> str:
    lines = []
    for hunk in hunks:
        for hline in hunk.lines:
            if hline.startswith("+"):
                lines.append(hline[1:])
    return "".join(lines)

def relative_path(self) -> str:
        p = self.new_path
        if p.startswith("b/"):
            p = p[2:]
        return p

def plan(query: str, context: str) -> list[dict]:
    """
    Call Anthropic Haiku to generate a step-by-step plan.
    Returns a list of {'file', 'action', 'reason'} dicts.
    Raises RuntimeError if the anthropic package is missing or the response is malformed.
    """
    try:
        import anthropic
    except ImportError as exc:
        raise RuntimeError("anthropic package required: pip install anthropic>=0.40") from exc

    client = anthropic.Anthropic()

    user_prompt = f"""TASK: {query}

CODEBASE CONTEXT:
{context}

Output the JSON plan now."""

    message = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        system=_PLAN_SYSTEM,
        messages=[{"role": "user", "content": user_prompt}],
    )

    raw = message.content[0].text.strip()

    # Strip markdown fences if present
    raw = re.sub(r"^```[^\n]*\n", "", raw, flags=re.MULTILINE)
    raw = re.sub(r"^```\s*$", "", raw, flags=re.MULTILINE)
    raw = raw.strip()

    try:
        steps = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise RuntimeError(f"Planner returned invalid JSON: {exc}\n\nRaw response:\n{raw}") from exc

    if not isinstance(steps, list):
        raise RuntimeError(f"Planner returned non-list JSON: {type(steps)}")

    validated: list[dict] = []
    for i, step in enumerate(steps):
        if not isinstance(step, dict):
            continue
        if "file" not in step or "action" not in step:
            continue
        validated.append({
            "file": step["file"],
            "action": step.get("action", "modify"),
            "reason": step.get("reason", ""),
        })

    if not validated:
        raise RuntimeError("Planner returned zero valid steps.")

    return validated

def paths_match(a: str, b: str) -> bool:
    na, nb = normalize_path(a), normalize_path(b)
    return na == nb or basename(na) == basename(nb)

def get_related_files(filepath: str, max_extra: int = 3) -> set[str]:
    """Return files in the same directory (up to max_extra)."""
    p = Path(filepath)
    if not p.parent.exists():
        return set()
    siblings = [
        str(f)
        for f in p.parent.iterdir()
        if f.suffix == ".py" and f != p and not f.name.startswith("__")
    ]
    return set(siblings[:max_extra])

def load(cls) -> "PolicySession":
        if _SESSION_FILE.exists():
            try:
                data = json.loads(_SESSION_FILE.read_text(encoding="utf-8"))
                return cls(**data)
            except Exception:
                pass
        return cls()

def save(self) -> None:
        _SESSION_DIR.mkdir(exist_ok=True)
        _SESSION_FILE.write_text(
            json.dumps(self.__dict__, indent=2), encoding="utf-8"
        )

def save_log(self) -> None:
        _LOG_DIR.mkdir(parents=True, exist_ok=True)
        log_path = _LOG_DIR / f"{self.session_id}.json"
        log_path.write_text(
            json.dumps(self.__dict__, indent=2), encoding="utf-8"
        )

def allow_file(self, filepath: str) -> None:
        norm = normalize_path(filepath)
        if not self.is_allowed(norm):
            self.allowed_files.append(norm)

def allow_with_neighbors(self, filepath: str) -> None:
        self.allow_file(filepath)
        for neighbor in get_related_files(filepath):
            self.allow_file(neighbor)

def _parse_fn(code: str) -> ast.FunctionDef | ast.AsyncFunctionDef | None:
    """Parse a code snippet and return its top-level function/method def."""
    try:
        tree = ast.parse(textwrap.dedent(code).strip())
    except SyntaxError:
        return None
    if not tree.body:
        return None
    top = tree.body[0]
    if isinstance(top, (ast.FunctionDef, ast.AsyncFunctionDef)):
        return top
    return None

def _strip_docstring(body: list[ast.stmt]) -> list[ast.stmt]:
    """Drop a leading docstring expression, if present."""
    if (
        body
        and isinstance(body[0], ast.Expr)
        and isinstance(body[0].value, ast.Constant)
        and isinstance(body[0].value.value, str)
    ):
        return body[1:]
    return body

def _is_log_call(stmt: ast.stmt) -> bool:
    if not isinstance(stmt, ast.Expr) or not isinstance(stmt.value, ast.Call):
        return False
    func = stmt.value.func
    if isinstance(func, ast.Name):
        return func.id in _PRINT_NAMES
    if isinstance(func, ast.Attribute):
        return func.attr in _LOG_ATTRS
    return False

def _is_thin_wrapper(fn: ast.FunctionDef | ast.AsyncFunctionDef) -> bool:
    """True for short helpers with no control flow — candidates for inlining."""
    body = _strip_docstring(fn.body)
    if not body or len(body) > _THIN_WRAPPER_MAX_STMTS:
        return False
    for stmt in body:
        if isinstance(stmt, (ast.If, ast.Try, ast.For, ast.While,
                              ast.AsyncFor, ast.With, ast.AsyncWith)):
            return False
    return True

def importance_score(node: Node) -> int:
    """Deterministic debugging-importance score for a node.

    Higher is more important.  Based on presence of control flow, raises,
    non-trivial returns, and call density — penalised for log-noise or
    thin-wrapper shape.
    """
    code = node.get("code", "")
    if not code:
        # File/class nodes have no body to score — treat as neutral.
        return 0

    fn = _parse_fn(code)
    if fn is None:
        return 0

    score = 0
    for child in ast.walk(fn):
        if isinstance(child, (ast.If, ast.IfExp, ast.Try)):
            score += 3
        elif isinstance(child, ast.Raise):
            score += 4
        elif isinstance(child, ast.Return):
            if child.value is None or isinstance(child.value, (ast.Constant, ast.Name)):
                score += 1   # trivial return
            else:
                score += 2   # non-trivial return
        elif isinstance(child, ast.Call):
            score += 1

    if _is_noise_body(fn):
        score -= 5
    if _is_thin_wrapper(fn):
        score -= 3

    return score

def classify(node: Node, entry_set: set[str], depth: int, score: int) -> Category:
    """Bucket a node into one of CORE / CRITICAL / SUPPORTING / NOISE."""
    nid = node["id"]
    ntype = node.get("type", "")

    if nid in entry_set:
        return "CORE"

    # Non-code nodes (file/class): kept as structural breadcrumbs only.
    if ntype not in ("function", "method"):
        return "SUPPORTING" if depth <= 1 else "NOISE"

    # Shape-based classification takes precedence over score:
    #   - log-heavy bodies → NOISE regardless of call density
    #   - thin wrappers   → SUPPORTING (to be inlined, not emitted in full)
    fn = _parse_fn(node.get("code", ""))
    if fn is not None:
        if _is_noise_body(fn):
            return "NOISE"
        if _is_thin_wrapper(fn):
            return "SUPPORTING"

    if score <= 0:
        return "NOISE"
    if depth == 1 and score >= 5:
        return "CRITICAL"
    if depth == 1:
        return "SUPPORTING"
    if score >= 7:
        return "CRITICAL"
    if score >= 3:
        return "SUPPORTING"
    return "NOISE"

def inline_hint(node: Node) -> str | None:
    """Return a one-line hint for a thin-wrapper node, or None if unsuitable."""
    code = node.get("code", "")
    fn = _parse_fn(code)
    if fn is None or not _is_thin_wrapper(fn):
        return None

    body = _strip_docstring(fn.body)
    if not body:
        return None

    try:
        lines = [ast.unparse(s) for s in body]
    except Exception:
        return None

    name = fn.name
    if len(body) == 1 and isinstance(body[0], ast.Return) and body[0].value is not None:
        return f"# {name}: {lines[0].removeprefix('return ').strip()}"
    return f"# {name}: " + "; ".join(lines)

def _structural_key(code: str) -> str:
    """Return a stable key that collapses name-only differences."""
    fn = _parse_fn(code)
    if fn is None:
        return code.strip()
    cloned = _AnonymiseNames().visit(fn)
    cloned.name = "_"
    ast.fix_missing_locations(cloned)
    try:
        return ast.unparse(cloned)
    except Exception:
        return code.strip()

def resolve_nodes(selected_ids: list[str], graph: dict) -> list[dict]:
    """
    Resolve node IDs to enriched dicts. When test-file nodes are in the pool,
    automatically pulls in the implementation nodes they call.
    """
    by_id: dict[str, dict] = {n["id"]: dict(n) for n in graph.get("nodes", []) if "id" in n}

    # Track full destination IDs (not just names) to enable cross-file expansion
    calls_map: dict[str, list[str]] = {}   # src_id -> [dst_id, ...]
    callers_map: dict[str, list[str]] = {} # dst_id -> [src_id, ...]
    for edge in graph.get("edges", []):
        if edge.get("type") == "calls":
            src, dst = edge["from"], edge["to"]
            calls_map.setdefault(src, []).append(dst)
            callers_map.setdefault(dst, []).append(src)

    resolved: dict[str, dict] = {}
    for nid in selected_ids:
        raw = by_id.get(nid)
        if not raw:
            continue
        resolved[nid] = _enrich(nid, raw, calls_map, callers_map)

    # For test-file nodes: follow calls into implementation files
    impl_ids: list[str] = []
    for nid, node in list(resolved.items()):
        if not _is_test_file(node.get("file", "")):
            continue
        for dst_id in calls_map.get(nid, []):
            if dst_id not in resolved and not _is_test_file(by_id.get(dst_id, {}).get("file", "")):
                impl_ids.append(dst_id)

    for nid in impl_ids:
        raw = by_id.get(nid)
        if raw:
            resolved[nid] = _enrich(nid, raw, calls_map, callers_map)

    # Narrowness fallback: if all nodes share one file, add their callees
    files = {n.get("file") for n in resolved.values()}
    if len(files) == 1:
        extra_ids = []
        for nid, node in list(resolved.items()):
            for dst_id in calls_map.get(nid, []):
                if dst_id not in resolved and by_id.get(dst_id, {}).get("type") in ("function", "method"):
                    extra_ids.append(dst_id)
                    if len(extra_ids) >= 4:
                        break
            if len(extra_ids) >= 4:
                break
        for nid in extra_ids:
            raw = by_id.get(nid)
            if raw:
                resolved[nid] = _enrich(nid, raw, calls_map, callers_map)

    return list(resolved.values())

def _alias_tokens(query_tokens: set[str]) -> set[str]:
    expanded = set(query_tokens)
    for t in query_tokens:
        expanded |= _ALIASES.get(t, set())
    return expanded

def _short_path(fpath: str) -> str:
    parts = fpath.replace("\\", "/").split("/")
    return parts[-1] if parts else fpath

def _extract_docstring(code: str) -> str:
    """Return first docstring text from a function, or empty string."""
    try:
        tree = ast.parse(code)
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                if (
                    node.body
                    and isinstance(node.body[0], ast.Expr)
                    and isinstance(node.body[0].value, ast.Constant)
                    and isinstance(node.body[0].value.value, str)
                ):
                    return node.body[0].value.value.lower()
    except SyntaxError:
        pass
    return ""

def _endpoint_relevance(node: dict, alias_tokens: set[str]) -> int:
    """Extra score when an endpoint's route path matches query intent."""
    code = node.get("code", "").lower()
    # Find route path strings in decorator args
    paths = re.findall(r'["\'](/[^"\']*)["\']', code)
    for path in paths:
        if any(t in path for t in alias_tokens if len(t) >= 3):
            return 2
    return 0

def _strip_comments(code: str) -> str:
    lines = []
    for line in code.splitlines():
        cleaned = re.sub(r'\s*#.*$', "", line).rstrip()
        if cleaned.strip():
            lines.append(cleaned)
    return "\n".join(lines)

def _strip_docstrings(code: str) -> str:
    try:
        tree = ast.parse(code)
    except SyntaxError:
        return code
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef, ast.Module)):
            if (
                node.body
                and isinstance(node.body[0], ast.Expr)
                and isinstance(node.body[0].value, ast.Constant)
                and isinstance(node.body[0].value.value, str)
            ):
                node.body.pop(0)
    return code

def _compress(code: str, max_lines: int = 18) -> str:
    code = _strip_docstrings(code)
    code = _strip_comments(code)
    lines = [l for l in code.splitlines() if l.strip()]
    if len(lines) > max_lines:
        lines = lines[:max_lines] + ["    ..."]
    return "\n".join(lines)

def _is_endpoint(node: dict) -> bool:
    code = node.get("code", "")
    return bool(_ENDPOINT_PATTERNS.search(code))

def _is_auth_fn(node: dict) -> bool:
    name_tokens = _tokens(node.get("name", ""))
    return bool(name_tokens & _AUTH_VERBS)

def _is_helper(node: dict) -> bool:
    name = node.get("name", "")
    return name.startswith("_") or any(
        t in name.lower() for t in ("helper", "util", "get_", "fetch_", "build_", "make_")
    )

def _coverage_select(scored: list[tuple[int, dict]], top_n: int) -> list[dict]:
    """
    Coverage-aware selection: guarantee at least one endpoint, one auth function,
    one helper/dependency. Fill remaining slots with top-scored diverse nodes.
    Max 2 nodes per file.
    """
    slots: dict[str, dict | None] = {"endpoint": None, "auth": None, "helper": None}
    remaining: list[tuple[int, dict]] = []

    for s, node in scored:
        if slots["endpoint"] is None and _is_endpoint(node):
            slots["endpoint"] = node
        elif slots["auth"] is None and _is_auth_fn(node):
            slots["auth"] = node
        elif slots["helper"] is None and _is_helper(node):
            slots["helper"] = node
        else:
            remaining.append((s, node))

    selected: list[dict] = [n for n in slots.values() if n is not None]
    seen_names = {n.get("name") for n in selected}
    file_counts: dict[str, int] = {}
    for n in selected:
        f = n.get("file", "")
        file_counts[f] = file_counts.get(f, 0) + 1

    for _, node in remaining:
        if len(selected) >= top_n:
            break
        name = node.get("name")
        f = node.get("file", "")
        if name in seen_names:
            continue
        if file_counts.get(f, 0) >= 2:
            continue
        selected.append(node)
        seen_names.add(name)
        file_counts[f] = file_counts.get(f, 0) + 1

    return selected

def _fallback_select(nodes: list[dict], top_n: int) -> list[dict]:
    fn_nodes = [n for n in nodes if n.get("type") in ("function", "method")]
    ranked = sorted(
        fn_nodes,
        key=lambda n: len(n.get("calls", [])) + len(n.get("callers", [])),
        reverse=True,
    )
    # Apply file diversity even in fallback
    seen_files: dict[str, int] = {}
    result = []
    for n in ranked:
        f = n.get("file", "")
        if seen_files.get(f, 0) < 2:
            result.append(n)
            seen_files[f] = seen_files.get(f, 0) + 1
        if len(result) >= top_n:
            break
    return result

def rank_and_select(nodes: list[dict], query: str, top_n: int = 4) -> list[dict]:
    query_tokens = _tokens(query)
    alias_tokens = _alias_tokens(query_tokens)

    scored: list[tuple[int, dict]] = []
    for node in nodes:
        s = _score(node, query_tokens, alias_tokens)
        if s == 0:
            continue
        scored.append((s, node))
    scored.sort(key=lambda x: x[0], reverse=True)

    if not scored:
        return _fallback_select(nodes, top_n)

    # Expand pool by 1-hop before coverage selection
    top_names = {n.get("name") for _, n in scored[:top_n]}
    by_name = {n.get("name"): n for n in nodes if n.get("name")}
    additions: list[tuple[int, dict]] = []
    caller_count = 0

    for _, node in scored[:top_n]:
        for callee in node.get("calls", []):
            if callee and callee not in top_names and callee in by_name:
                s = _score(by_name[callee], query_tokens, alias_tokens)
                if s >= 2:
                    additions.append((s, by_name[callee]))
                    top_names.add(callee)
        for caller in node.get("callers", []):
            if caller_count >= 2:
                break
            if caller and caller not in top_names and caller in by_name:
                s = _score(by_name[caller], query_tokens, alias_tokens)
                if s >= 2:
                    additions.append((s, by_name[caller]))
                    top_names.add(caller)
                    caller_count += 1

    all_scored = sorted(scored + additions, key=lambda x: x[0], reverse=True)

    # Dedup
    seen: set[str] = set()
    deduped: list[tuple[int, dict]] = []
    for s, n in all_scored:
        name = n.get("name")
        if name and name not in seen:
            seen.add(name)
            deduped.append((s, n))

    return _coverage_select(deduped, top_n)

def format_output(_query: str, nodes: list[dict]) -> str:
    if not nodes:
        return "NO_CONTEXT_FOUND"

    by_file: dict[str, list[dict]] = {}
    for node in nodes:
        key = _short_path(node.get("file", "unknown"))
        by_file.setdefault(key, []).append(node)

    blocks: list[str] = []
    total = 0

    for fname, fnodes in by_file.items():
        blocks.append(f"[{fname}]")
        for node in fnodes:
            compressed = _compress(node.get("code", ""))
            lines = compressed.splitlines()
            if total + len(lines) > 55:
                remaining = 55 - total
                if remaining <= 0:
                    break
                lines = lines[:remaining] + ["    ..."]
            blocks.extend(lines)
            blocks.append("")
            total += len(lines) + 1

    return "\n".join(l for l in blocks if l.strip()).strip()

def _tokenize(identifier: str) -> list[str]:
    """Split snake_case / camelCase / dotted / path-like strings into lower tokens."""
    identifier = _EXT_STRIP.sub("", identifier)
    tokens: list[str] = []
    for word in re.split(r"[^a-zA-Z0-9]+", identifier):
        if not word:
            continue
        parts = _CAMEL_SPLIT.findall(word) or [word]
        tokens.extend(p.lower() for p in parts)
    return tokens

def _expand_keywords(
    keywords: list[str],
) -> tuple[set[str], set[str], set[str]]:
    """Return ``(primary, synonyms, secondary)`` token sets.

    Three tiers of signal strength
    --------------------------------
    * **primary** — the user's own keywords, tokenised.  These must appear in
      a node's name or file path for the entry-point hard gate to pass.
    * **synonyms** — first-level expansions from ``_SYNONYMS``.  They add
      score bonuses but cannot pass the hard gate alone.
    * **secondary** — second-level expansions (synonyms of synonyms).  They
      provide a weak additional signal (+1) for code that uses indirect
      terminology (e.g. ``jwt`` or ``session`` when the user queried
      ``login``).  They cannot affect the hard gate at all.

    Example (query = "login")
    -------------------------
    primary   = {"login"}
    synonyms  = {"auth", "authenticate", "signin", "token", "session", "jwt"}
    secondary = {"bearer", "claim", "cookie", "credential", "security", …}
    """
    primary: set[str] = set()
    for kw in keywords:
        primary.update(_tokenize(kw))

    # Level-1 expansion.
    synonyms: set[str] = set()
    for kw in primary:
        for syn in _SYNONYMS.get(kw, ()):
            if syn not in primary:
                synonyms.add(syn)

    # Level-2 expansion: fan out from synonyms, excluding already-known tokens.
    secondary: set[str] = set()
    for syn in synonyms:
        for syn2 in _SYNONYMS.get(syn, ()):
            if syn2 not in primary and syn2 not in synonyms:
                secondary.add(syn2)

    return primary, synonyms, secondary

def _weighted_keywords(raw_keywords: list[str]) -> dict[str, int]:
    """Return a mapping of ``token -> weight`` for the full expanded keyword set.

    Weight tiers
    ------------
    * ``3`` — user's exact words (highest confidence).
    * ``2`` — strong first-level synonyms (close semantic match).
    * ``1`` — second-level / related concepts (weak signal).
    * ``0`` — generic terms (filtered out; not included in result).

    Example (query = "login")
    -------------------------
    ``{"login": 3, "auth": 2, "jwt": 2, "token": 2, "session": 2,
       "authenticate": 2, "signin": 2, "bearer": 1, "cookie": 1, ...}``
    """
    weights: dict[str, int] = {}

    # Exact user tokens — weight 3.
    primary: set[str] = set()
    for kw in raw_keywords:
        for tok in _tokenize(kw):
            primary.add(tok)
            weights[tok] = 3

    # First-level synonyms — weight 2 (skip generic terms).
    synonyms: set[str] = set()
    for kw in primary:
        for syn in _SYNONYMS.get(kw, ()):
            if syn not in primary and syn not in _GENERIC_TERMS:
                synonyms.add(syn)
                if weights.get(syn, 0) < 2:
                    weights[syn] = 2

    # Second-level synonyms — weight 1 (skip generic terms).
    for syn in synonyms:
        for syn2 in _SYNONYMS.get(syn, ()):
            if syn2 not in primary and syn2 not in synonyms and syn2 not in _GENERIC_TERMS:
                if syn2 not in weights:   # don't downgrade a higher-tier token
                    weights[syn2] = 1

    return weights

def _compute_fan_in(edges: list[Edge]) -> dict[str, int]:
    """Count incoming ``calls`` edges per node — proxy for importance."""
    fan_in: dict[str, int] = {}
    for edge in edges:
        if edge.get("type") == "calls":
            fan_in[edge["to"]] = fan_in.get(edge["to"], 0) + 1
    return fan_in

def _is_test_path(file_part: str) -> bool:
    """Return True when the file path contains a test/mock/fixture segment."""
    path_tokens = set(_tokenize(file_part))
    return bool(path_tokens & _TEST_PATH_TOKENS)

def _is_important_dir(file_part: str) -> bool:
    """Return True when the file path contains a high-signal directory name."""
    segments = {seg.lower() for seg in re.split(r"[/\\]", file_part) if seg}
    return bool(segments & _IMPORTANT_DIRS)

def _type_preference(ntype: str) -> int:
    """Sort tiebreak: prefer concrete code symbols over files/classes."""
    return {"function": 0, "method": 0, "class": 1, "file": 2}.get(ntype, 3)

def _fallback_entries(
    nodes: list[Node],
    edges: list[Edge],
    max_entries: int,
) -> list[str]:
    """Return highest-degree function/method nodes when nothing matched."""
    degree: dict[str, int] = {}
    for edge in edges:
        degree[edge["from"]] = degree.get(edge["from"], 0) + 1
        degree[edge["to"]] = degree.get(edge["to"], 0) + 1

    code_nodes = [n for n in nodes if n["type"] in ("function", "method")]
    if not code_nodes:
        # Graph without any code — fall back to file nodes.
        code_nodes = [n for n in nodes if n["type"] == "file"]
    code_nodes.sort(key=lambda n: (-degree.get(n["id"], 0), n["id"]))
    return [n["id"] for n in code_nodes[:max_entries]]

def _build_adjacency(edges: list[Edge]) -> tuple[dict[str, list[tuple[str, str]]], dict[str, list[tuple[str, str]]]]:
    """Build forward and reverse adjacency maps from the edge list.

    Returns ``(outgoing, incoming)`` where each value is a list of
    ``(neighbour_id, edge_type)`` tuples.
    """
    outgoing: dict[str, list[tuple[str, str]]] = {}
    incoming: dict[str, list[tuple[str, str]]] = {}
    for edge in edges:
        src, dst, etype = edge["from"], edge["to"], edge["type"]
        outgoing.setdefault(src, []).append((dst, etype))
        incoming.setdefault(dst, []).append((src, etype))
    return outgoing, incoming

def traverse_graph(
    entry_ids: list[str],
    nodes: list[Node],
    edges: list[Edge],
    max_depth: int = _MAX_DEPTH,
) -> dict[str, int]:
    """BFS from each entry node following calls, imports, and reverse-calls.

    Returns a mapping of ``node_id → minimum depth`` reached.  Depth 0 means
    the node is an entry point; depth 1 means one hop away, etc.
    """
    node_ids: set[str] = {n["id"] for n in nodes}
    outgoing, incoming = _build_adjacency(edges)

    # Edge types to follow in each direction.
    _follow_out: frozenset[str] = frozenset({"calls", "imports", "contains", "has_method"})
    _follow_in: frozenset[str] = frozenset({"calls"})   # reverse-calls for debugging

    visited: dict[str, int] = {}
    queue: deque[tuple[str, int]] = deque()

    for eid in entry_ids:
        if eid in node_ids:
            queue.append((eid, 0))
            visited[eid] = 0

    while queue:
        current, depth = queue.popleft()
        if depth >= max_depth:
            continue

        # Forward edges
        for neighbour, etype in outgoing.get(current, []):
            if etype in _follow_out and neighbour not in visited:
                visited[neighbour] = depth + 1
                queue.append((neighbour, depth + 1))

        # Reverse call edges (who calls *current*)
        for neighbour, etype in incoming.get(current, []):
            if etype in _follow_in and neighbour not in visited:
                visited[neighbour] = depth + 1
                queue.append((neighbour, depth + 1))

    return visited

def _module_scores(
    visited: dict[str, int],
    node_map: dict[str, Node],
    kw_weights: dict[str, int],
) -> dict[str, int]:
    """Compute a per-file relevance score for every module touched by traversal.

    Rubric
    ------
    * ``+3``  file path contains a module-level keyword (auth/login/security/…).
    * ``+2``  file path contains any query keyword (weight >= 2).
    * ``+2``  the file contains ≥2 visited nodes whose symbol names hit a
              keyword with weight >= 2.
    """
    strong_kws = {k for k, w in kw_weights.items() if w >= 2}

    relevant_fn_count: dict[str, int] = {}
    for nid in visited:
        node = node_map.get(nid)
        if node is None or node.get("type") not in ("function", "method"):
            continue
        file = _file_of(nid)
        _, _, sym = nid.rpartition(":")
        name_tokens = set(_tokenize(sym))
        if name_tokens & strong_kws:
            relevant_fn_count[file] = relevant_fn_count.get(file, 0) + 1

    all_files: set[str] = {_file_of(nid) for nid in visited}

    scores: dict[str, int] = {}
    for file in all_files:
        s = 0
        file_tokens = set(_tokenize(file))
        path_segments = {seg.lower() for seg in re.split(r"[/\\]", file) if seg}

        if path_segments & _MODULE_KEYWORDS:
            s += 3
        if file_tokens & strong_kws:
            s += 2
        if relevant_fn_count.get(file, 0) >= 2:
            s += 2
        scores[file] = s
    return scores

def estimate_tokens(text: str) -> int:
    """Rough token count: characters / 4 (GPT-style approximation)."""
    return max(1, len(text) // 4)

def _top_level_names(tree: ast.Module) -> set[str]:
    return {
        node.name
        for node in ast.iter_child_nodes(tree)
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef))
    }

def validate_syntax(code: str, filename: str = "<generated>") -> ValidationResult:
    """Return ValidationResult with ok=False if code has a SyntaxError."""
    if not code.strip():
        return ValidationResult(ok=True)
    try:
        ast.parse(code)
        return ValidationResult(ok=True)
    except SyntaxError as exc:
        return ValidationResult(
            ok=False,
            errors=[f"SyntaxError line {exc.lineno}: {exc.msg}"],
        )

def validate_no_duplicates(existing_code: str, additions: str) -> ValidationResult:
    """Ensure additions do not redefine top-level names already in existing_code."""
    if not existing_code.strip() or not additions.strip():
        return ValidationResult(ok=True)
    try:
        existing_names = _top_level_names(ast.parse(existing_code))
        new_names = _top_level_names(ast.parse(additions))
    except SyntaxError:
        return ValidationResult(ok=True)  # syntax validator handles this

    duplicates = existing_names & new_names
    if duplicates:
        return ValidationResult(
            ok=False,
            errors=[f"Would overwrite existing definitions: {', '.join(sorted(duplicates))}"],
        )
    return ValidationResult(ok=True)

def validate_patch(original: str, patched: str, filename: str = "<patched>") -> ValidationResult:
    """Run all validations on the patched file content."""
    return validate_syntax(patched, filename)

def _collect_source_files(root: Path) -> list[Path]:
    files: list[Path] = []
    for path in root.rglob("*"):
        if path.suffix not in _WATCHED_EXTENSIONS:
            continue
        if any(part in _IGNORE_DIRS for part in path.parts):
            continue
        files.append(path)
    return sorted(files)

def _is_relevant(self, path_str: str) -> bool:
        p = Path(path_str)
        if p.suffix not in _WATCHED_EXTENSIONS:
            return False
        return not any(part in _IGNORE_DIRS for part in p.parts)

def _do_rebuild(self) -> None:
        try:
            nodes, edges, ms = rebuild_graph(self._root)
            print(f"Graph updated: {nodes} nodes, {edges} edges ({ms:.0f}ms)", flush=True)
        except Exception as exc:
            print(f"Graph rebuild failed: {exc}", flush=True)
            logger.exception("Rebuild error")

def on_created(self, event: FileSystemEvent) -> None:
        if not event.is_directory and self._is_relevant(event.src_path):
            self._schedule_rebuild()

def on_modified(self, event: FileSystemEvent) -> None:
        if not event.is_directory and self._is_relevant(event.src_path):
            self._schedule_rebuild()

def on_deleted(self, event: FileSystemEvent) -> None:
        if not event.is_directory and self._is_relevant(event.src_path):
            self._schedule_rebuild()

def on_moved(self, event: FileSystemEvent) -> None:
        src_ok = self._is_relevant(event.src_path)
        dst_ok = self._is_relevant(event.dest_path)  # type: ignore[attr-defined]
        if not event.is_directory and (src_ok or dst_ok):
            self._schedule_rebuild()

def main() -> None:
    raw = sys.stdin.read()
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        sys.exit(0)

    tool_name: str = payload.get("tool_name", "")
    if tool_name not in _GATED_TOOLS:
        sys.exit(0)

    tool_input: dict = payload.get("tool_input", {})
    filepath = None
    for key in ("file_path", "path", "file"):
        val = tool_input.get(key)
        if val and isinstance(val, str):
            filepath = normalize_path(val)
            break

    if not filepath:
        sys.exit(0)

    session = PolicySession.load()

    # Record successful read/edit for audit trail
    entry = {"tool": tool_name, "file": filepath}
    if not hasattr(session, "_tool_uses"):
        session.__dict__.setdefault("_tool_uses", [])
    session.__dict__["_tool_uses"].append(entry)

    session.save()
    session.save_log()
    sys.exit(0)

def _load_graph() -> dict | None:
    if not _GRAPH_PATH.exists():
        return None
    try:
        return json.loads(_GRAPH_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None
